#include <bits/stdc++.h>
using namespace std; 

const int infinity = INT_MAX;

bool cmp(pair<int,int> a, pair<int,int> b) {
    if(a.second * b.first > a.first * b.second) return 1;
    return 0;
}

// Pick items from index idx, weight remaining
int fractional_knapsack(int idx, vector<pair<int,int>> &items, int weight) {
    double ans = 0;
    for(int i = idx; i < items.size(); i++) {
        if(items[i].first <= weight) {
            weight -= items[i].first;
            ans += items[i].second;
        }
        else {
            double fraction = (double)weight / items[i].first;
            ans += fraction * items[i].second;
        }
    }

    return (int)floor(ans);
}

int branch_and_bound(int n, int wmax, vector<pair<int,int>> items) {
    // q stores {cost + lower_bound, weight of the items, cost of the items, next item to consider}
    priority_queue<array<int,4>> q;

    // invert the sign of all the items
    for(int i = 0; i < n; i++) items[i].second = -items[i].second;

    // Presort to perform fractional knapsack
    sort(items.begin(), items.end(), cmp);

    int upper_bound = infinity;

    q.push({0 + fractional_knapsack(0, items, wmax), 0, 0, 0});

    while(!q.empty()) {
        int cost_lower_bound = (q.top())[0];
        int weight = (q.top())[1];
        int cost = (q.top())[2];
        int item = (q.top())[3];
        q.pop();

        if(cost_lower_bound >= upper_bound) {
            continue;
        }

        // Atleast a solution with "cost" is promised
        upper_bound = min(upper_bound, cost);

        for(int i = item; i < n; i++) {
            if(items[i].first + weight > wmax) { // weight limit exceeded
                continue;
            }
            int new_cost = cost + items[i].second;
            int new_weight = weight + items[i].first;
            int cost_lower_bound = new_cost + fractional_knapsack(i, items, wmax - new_weight);
            q.push({cost_lower_bound, new_weight, new_cost, i + 1});
        }
    }

    return -upper_bound; // invert the sign
}

int main() {
    int n; cin >> n;
    int wmax; cin >> wmax;
    vector<pair<int,int>> items(n);
    for(int i = 0; i < n; i++) {
        cin >> items[i].first >> items[i].second;
    }
    cout << branch_and_bound(n, wmax, items);

    return 0;
}

