#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <math.h>

#define infinity INT_MAX

typedef struct {
    int first;
    int second;
} Pair;

typedef struct {
    int first;
    int second;
    int third;
    int fourth;
} Array;

int cmp(const void *a, const void *b) {
    Pair *pa = (Pair *)a;
    Pair *pb = (Pair *)b;
    return (double)pb->second * pa->first - (double)pa->second * pb->first;
}

// Min-heap for priority queue
void push(Array heap[], int *size, Array value) {
    int i = (*size)++;
    while (i && value.first < heap[(i - 1) / 2].first) {
        heap[i] = heap[(i - 1) / 2];
        i = (i - 1) / 2;
    }
    heap[i] = value;
}

void pop(Array heap[], int *size) {
    Array last = heap[--(*size)];
    int i = 0, child;
    while ((child = 2 * i + 1) < *size) {
        if (child + 1 < *size && heap[child + 1].first < heap[child].first)
            child++;
        if (last.first <= heap[child].first)
            break;
        heap[i] = heap[child];
        i = child;
    }
    heap[i] = last;
}

Array top(Array heap[]) {
    return heap[0];
}

int fractional_knapsack(int idx, Pair items[], int size, int weight) {
    double ans = 0.0;
    for (int i = idx; i < size; i++) {
        if (items[i].first <= weight) {
            weight -= items[i].first;
            ans += items[i].second;
        } else {
            double fraction = (double)weight / items[i].first;
            ans += fraction * items[i].second;
            break;
        }
    }
    return (int)floor(ans);
}

int branch_and_bound(int n, int wmax, Pair items[]) {
    Array heap[10000];
    int size = 0;

    // Invert the sign of all the items
    for (int i = 0; i < n; i++) items[i].second = -items[i].second;

    // Pre-sort to perform fractional knapsack
    qsort(items, n, sizeof(Pair), cmp);

    int upper_bound = infinity;

    Array start = {0 + fractional_knapsack(0, items, n, wmax), 0, 0, 0};
    push(heap, &size, start);

    while (size > 0) {
        Array current = top(heap);
        pop(heap, &size);

        int cost_lower_bound = current.first;
        int weight = current.second;
        int cost = current.third;
        int item = current.fourth;

        if (cost_lower_bound >= upper_bound) {
            continue;
        }

        upper_bound = cost < upper_bound ? cost : upper_bound;

        for (int i = item; i < n; i++) {
            if (items[i].first + weight > wmax) { // weight limit exceeded
                continue;
            }
            int new_cost = cost + items[i].second;
            int new_weight = weight + items[i].first;
            int cost_lower_bound = new_cost + fractional_knapsack(i, items, n, wmax - new_weight);
            Array next = {cost_lower_bound, new_weight, new_cost, i + 1};
            push(heap, &size, next);
        }
    }

    return -upper_bound; // Invert the sign back
}

int main() {
    int n, wmax;
    scanf("%d %d", &n, &wmax);
    Pair items[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &items[i].first, &items[i].second);
    }
    printf("%d\n", branch_and_bound(n, wmax, items));
    return 0;
}

